// ── TEMPORADA ────────────────────────────────────────────────
async function carregarTemporada() {
  try {
    const { data, error } = await supabaseClient
      .from('seasons')
      .select('*')
      .eq('status', 'active')
      .single();
    
    if (error || !data) return null;

    const fim = new Date(data.end_date);
    const hoje = new Date();
    const diff = fim - hoje;
    const dias = Math.ceil(diff / (1000 * 60 * 60 * 24));
    
    temporadaAtiva = {
      nome: data.name,
      id: data.id,
      restante: dias > 0 ? dias : 0
    };
    return temporadaAtiva;
  } catch (e) {
    return null;
  }
}

function getTemporadaHtml() {
  if (!temporadaAtiva) return '';
  return `<div style="font-size:10px; color:#ffcc00; margin-top:2px;">
    🏆 ${escapeHtml(temporadaAtiva.nome)} (${temporadaAtiva.restante} dias restantes)
  </div>`;
}
function iniciarFlashAba(count) {
  if (titleFlashInterval) return;
  titleFlashInterval = setInterval(() => {
    document.title = document.title === docTitleBase
      ? `(${count}) Nova mensagem!`
      : docTitleBase;
  }, 1000);
}
function pararFlashAba() {
  if (titleFlashInterval) { clearInterval(titleFlashInterval); titleFlashInterval = null; }
  document.title = docTitleBase;
  unreadMessages = 0;
}
document.addEventListener('visibilitychange', () => {
  if (!document.hidden) pararFlashAba();
});

