// ── TABS ─────────────────────────────────────────────────────
function alternarTab(tab) {
  const tabEntrar = document.getElementById('tab-entrar');
  const tabCad = document.getElementById('tab-cadastrar');
  if (!tabEntrar || !tabCad) return;
  tabEntrar.style.display    = tab==='entrar'    ? 'flex' : 'none';
  tabCad.style.display = tab==='cadastrar' ? 'flex' : 'none';
  document.querySelectorAll('.tab-btn').forEach((b,i) => {
    b.classList.toggle('active',(i===0&&tab==='entrar')||(i===1&&tab==='cadastrar'));
  });
}

// ── LOGIN ────────────────────────────────────────────────────
async function fazerLogin() {
  const email = document.getElementById('login-email').value.trim();
  const senha = document.getElementById('login-senha').value;
  const msg   = document.getElementById('msg-login');
  if (!email||!senha) { msg.textContent='Preencha e-mail e senha.'; return; }
  msg.style.color='#ffddaa'; msg.textContent='Entrando...';
  const { data, error } = await supabaseClient.auth.signInWithPassword({ email, password: senha });
  if (error) { msg.style.color='#ffaaaa'; msg.textContent='E-mail ou senha incorretos.'; return; }
  currentUser = data.user;
  await supabaseClient.from('profiles').update({ status: 'online' }).eq('id', currentUser.id);
  await verificarPerfil();
}

// ── RECUPERAÇÃO DE SENHA ─────────────────────────────────────
async function recuperarSenha() {
  const email = document.getElementById('login-email').value.trim();
  const msg = document.getElementById('msg-login');
  
  if (!email) {
    msg.style.color = '#ffaaaa';
    msg.textContent = 'Digite seu e-mail acima primeiro.';
    return;
  }

  msg.style.color = '#ffddaa';
  msg.textContent = 'Enviando link de recuperação...';

  const { error } = await supabaseClient.auth.resetPasswordForEmail(email, {
    redirectTo: window.location.origin,
  });

  if (error) {
    msg.style.color = '#ffaaaa';
    msg.textContent = 'Erro: ' + error.message;
  } else {
    msg.style.color = '#aaffaa';
    msg.textContent = '📧 Link enviado! Verifique seu e-mail.';
  }
}

async function salvarNovaSenha(inputId) {
  const novaSenha = document.getElementById(inputId).value;
  if (!novaSenha || novaSenha.length < 6) {
    mostrarNotificacao('A nova senha deve ter pelo menos 6 caracteres.');
    return;
  }

  try {
    const { error } = await supabaseClient.auth.updateUser({
      password: novaSenha,
    });

    if (error) {
      mostrarNotificacao('Erro ao atualizar senha: ' + error.message);
    } else {
      mostrarNotificacao('✅ Senha atualizada com sucesso!');
      document.getElementById(inputId).value = ''; // Limpa o campo
      if (inputId === 'nova-senha-recuperacao') fecharJanela('janela-reset-pw'); // Fecha a janela de recuperação se for o caso
    }
  } catch (e) { console.error('Erro ao salvar nova senha:', e); mostrarNotificacao('Erro inesperado ao atualizar senha.'); }
}
// Monitorar se o usuário veio pelo link de recuperação
