async function publicarPost() {
  const title=document.getElementById('fl-title').value.trim();
  const caption=document.getElementById('fl-caption').value.trim();
  const btn=document.querySelector('.fl-btn-postar');
  if(!fotologPostFile&&!caption&&!title){mostrarNotificacao('Adicione uma foto, título ou texto!');return;}

  // Verifica se o usuário já postou hoje
  const hoje = new Date().toISOString().split('T')[0]; // Data atual no formato YYYY-MM-DD (UTC)
  const { count, error: countError } = await supabaseClient
    .from('posts')
    .select('*', { count: 'exact', head: true })
    .eq('user_id', currentUser.id)
    .gte('created_at', hoje); // Verifica posts criados a partir do início do dia

  if (countError) { mostrarNotificacao('Erro ao verificar posts diários.'); return; }
  if (count > 0) { mostrarNotificacao('Você já fez seu post diário! Volte amanhã.'); return; }

  btn.textContent='Publicando...'; btn.disabled=true;
  let imageUrl=null;
  if(fotologPostFile){
    const compressedFile = await comprimirImagem(fotologPostFile,800);
    try {
      imageUrl = await uploadToCloudinary(compressedFile, 'posts');
    } catch (e) {
      mostrarNotificacao('Erro ao fazer upload da foto do post.');
      btn.textContent='Publicar (Gold Camera)';
      btn.disabled = false;
      return;
    }
  }
  const {data:postData,error}=await supabaseClient.from('posts').insert([{
    user_id:currentUser.id, nickname:currentProfile.nickname,
    avatar_url:currentProfile.avatar_url, color:currentProfile.color,
    image_url:imageUrl, caption:caption, title:title, xp_awarded:true
  }]).select().single();
  if(!error&&postData){
    await adicionarXP(10,'post no Fotolog');
    const feed=document.getElementById('fotolog-feed');
    if(feed){
      const semPosts=feed.querySelector('.fl-loading'); if(semPosts)semPosts.remove();
      feed.insertBefore(criarCardPost(postData, []), feed.firstChild);
    }
    fotologPostFile=null;
    document.getElementById('fl-foto-preview').style.display='none';
    document.getElementById('fl-foto-placeholder').style.display='block';
    document.getElementById('fl-title').value='';
    document.getElementById('fl-caption').value='';
    document.getElementById('fl-foto-input').value='';
  }
  btn.textContent='Publicar (Gold Camera)'; btn.disabled=false;
}

async function carregarFeed() {
  const feed=document.getElementById('fotolog-feed'); if(!feed)return;
  const {data,error}=await supabaseClient
    .from('posts')
    .select('*, profiles(is_verified)')
    .order('created_at',{ascending:false})
    .limit(30);

  if(error){feed.innerHTML='<div class="fl-loading">Erro ao carregar.</div>';return;}
  feed.innerHTML='';
  if(!data || !data.length){feed.innerHTML='<div class="fl-loading">Nenhum post ainda. Seja o primeiro! 📸</div>';return;}

  // Ordenação: 1. Verificados, 2. Amigos, 3. Resto (mantendo a ordem cronológica interna)
  data.sort((a, b) => {
    const getRank = (p) => {
      if (p.profiles?.is_verified) return 2;
      if (cacheAmizades.get(p.user_id) === 'accepted') return 1;
      return 0;
    };
    const rankA = getRank(a);
    const rankB = getRank(b);
    return rankB - rankA; // Se o rank for igual, o JS mantém a ordem original (cronológica da query)
  });

  // Otimização: Busca todos os comentários dos posts carregados em uma única query (evita N+1)
  const postIds = data.map(p => p.id);
  const { data: allComments } = await supabaseClient
    .from('comments')
    .select('*')
    .in('post_id', postIds)
    .order('created_at', { ascending: true });

  data.forEach(post => {
    const postComments = allComments ? allComments.filter(c => c.post_id === post.id) : [];
    feed.appendChild(criarCardPost(post, postComments));
  });
}

function criarCardPost(post,comments){
  const card=document.createElement('div');
  card.className='fl-card'; card.id='post-'+post.id;
  const verifiedBadge = post.profiles?.is_verified ? '<span title="Perfil Verificado (Bad Idea)" style="margin-left:4px; font-size:12px; cursor:help;">⭐</span>' : '';
  const av=post.avatar_url
    ?`<img src="${post.avatar_url}" class="fl-card-avatar" alt="">`
    :`<div class="fl-card-avatar-inicial" style="background:${post.color||'#0000cc'}">${post.nickname.charAt(0).toUpperCase()}</div>`;
  const dt=new Date(post.created_at).toLocaleDateString('pt-BR',{day:'2-digit',month:'2-digit',year:'2-digit',hour:'2-digit',minute:'2-digit'});
  const comHtml=comments.map(c=>`<div class="fl-comment"><span class="fl-comment-nick" style="color:${c.color||'#0000cc'}">${escapeHtml(c.nickname)}:</span> <span>${escapeHtml(c.content)}</span></div>`).join('');
  card.innerHTML=`
    <div class="fl-card-header">${av}<div><div class="fl-card-nick" style="color:${post.color||'#0000cc'}">${escapeHtml(post.nickname)}${verifiedBadge}${getBotaoAmizade(post.user_id)}</div><div class="fl-card-data">${dt}</div></div></div>
    ${post.title?`<div class="fl-card-title">${escapeHtml(post.title)}</div>`:''}
    ${post.image_url?`<img src="${post.image_url}" class="fl-card-img" alt="">`:''}
    ${post.caption?`<div class="fl-card-caption">${escapeHtml(post.caption)}</div>`:''}
    <div class="fl-card-actions">
      <button class="fl-comment-btn" onclick="toggleComentarios(${post.id})">💬 ${comments.length}</button>
      ${post.user_id === currentUser.id ? `<button class="fl-delete-btn" onclick="removerPost('${post.id}')">✕ Remover</button>` : ''}
    </div>
    <div class="fl-comments-area" id="comments-${post.id}">
      <div class="fl-comments-list" id="comments-list-${post.id}">${comHtml}</div>
      <div class="fl-comment-input-row">
        <input type="text" id="comment-input-${post.id}" placeholder="deixe um comentário... (+5 XP)" maxlength="200"
          onkeydown="if(event.key==='Enter')enviarComentario(${post.id})">
        <button onclick="enviarComentario(${post.id})">ok</button>
      </div>
    </div>`;
  return card;
}

function toggleComentarios(postId){
  const a=document.getElementById('comments-'+postId); if(!a)return;
  a.classList.toggle('aberto');
  if(a.classList.contains('aberto')){const i=document.getElementById('comment-input-'+postId);if(i)i.focus();}
}
async function enviarComentario(postId){
  const input=document.getElementById('comment-input-'+postId);
  const text=input.value.trim(); if(!text)return; input.value='';

  const { data: post } = await supabaseClient.from('posts').select('user_id').eq('id', postId).single();

  const { data: commentData, error } = await supabaseClient.from('comments').insert([{
    post_id:postId, user_id:currentUser.id, nickname:currentProfile.nickname,
    avatar_url:currentProfile.avatar_url, color:currentProfile.color, content:text, xp_awarded:true
  }]).select().single();

  if(!error && commentData){
    if (post && post.user_id !== currentUser.id) {
      const { count: commentsOnPost } = await supabaseClient.from('comments')
        .select('*', { count: 'exact', head: true }).eq('post_id', postId).eq('user_id', currentUser.id);
      
      if (commentsOnPost === 1) {
        const hoje = new Date().toISOString().split('T')[0];
        const { count: totalHoje } = await supabaseClient.from('comments')
          .select('*', { count: 'exact', head: true })
          .eq('user_id', currentUser.id).gte('created_at', hoje);
        
        if (totalHoje <= 10) { // Limite de 50 XP (10 comentários de 5 XP cada)
          await adicionarXP(5, 'comentou no Fotolog');
        }
      }
    }

    const lista=document.getElementById('comments-list-'+postId);
    if(lista){
      const d=document.createElement('div'); d.className='fl-comment';
      d.innerHTML=`<span class="fl-comment-nick" style="color:${currentProfile.color}">${escapeHtml(currentProfile.nickname)}:</span> <span>${escapeHtml(text)}</span>`;
      lista.appendChild(d);
      const btn=document.querySelector(`#post-${postId} .fl-comment-btn`);
      if(btn)btn.textContent=`💬 ${lista.children.length}`;
    }
  }
}

async function removerPost(postId) {
  if (!confirm('Tem certeza que deseja remover este post? Esta ação é irreversível e removerá também todos os comentários associados.')) {
    return;
  }

  // Primeiro, remove os comentários associados ao post
  const { error: commentsError } = await supabaseClient.from('comments').delete().eq('post_id', postId);
  if (commentsError) {
    console.error('Erro ao remover comentários:', commentsError);
    mostrarNotificacao('Erro ao remover comentários do post.');
    return;
  }

  const { error: postError } = await supabaseClient.from('posts').delete().eq('id', postId);
  if (postError) {
    mostrarNotificacao('Erro ao remover post: ' + postError.message);
  } else {
    mostrarNotificacao('✅ Post removido com sucesso!');
    const postElement = document.getElementById('post-' + postId);
    if (postElement) postElement.remove();
  }
}

function iniciarRealtimeFotolog(){
  if(fotologRealtime)supabaseClient.removeChannel(fotologRealtime);
  fotologRealtime=supabaseClient.channel('fotolog-updates')
    .on('postgres_changes',{event:'INSERT',schema:'public',table:'posts'},async p=>{
      const feed=document.getElementById('fotolog-feed'); if(!feed)return;
      if(p.new.user_id===currentUser.id)return;
      const semPosts=feed.querySelector('.fl-loading'); if(semPosts)semPosts.remove();
      feed.insertBefore(criarCardPost(p.new, []), feed.firstChild);
    })
    .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'comments' }, p => {
      if (p.new.user_id === currentUser.id) return;
      const lista = document.getElementById('comments-list-' + p.new.post_id);
      if (lista) {
        const d = document.createElement('div'); d.className = 'fl-comment';
        d.innerHTML = `<span class="fl-comment-nick" style="color:${p.new.color || '#0000cc'}">${escapeHtml(p.new.nickname)}:</span> <span>${escapeHtml(p.new.content)}</span>`;
        lista.appendChild(d);
        lista.scrollTop = lista.scrollHeight;

        const btn = document.querySelector(`#post-${p.new.post_id} .fl-comment-btn`);
        if (btn) btn.textContent = `💬 ${lista.children.length}`;
      }
    })
    .subscribe();
}

function mostrarMSNPopup(titulo, msg, avatarUrl) {
  tocarSomOnline(); // Som clássico de entrada do MSN
  const popup = document.createElement('div');
  popup.className = 'msn-popup';
  
  const av = avatarUrl 
    ? `<img src="${avatarUrl}" style="width:34px; height:34px; border-radius:3px; object-fit:cover; border:1px solid #716f64;">`
    : `<div style="width:34px; height:34px; border-radius:3px; background:#3a6ec8; color:white; display:flex; align-items:center; justify-content:center; font-size:16px; font-weight:bold; border:1px solid #716f64;">?</div>`;

  popup.innerHTML = `
    <div class="msn-popup-header">${iconTag('msn', 12)} ${titulo}</div>
    <div style="display:flex; align-items:center; gap:10px; padding:2px 0;">
      ${av}
      <div class="msn-popup-body">${msg}</div>
    </div>
  `;
  
  document.body.appendChild(popup);
  
  // Sobe, fica 3 segundos, e desce
  setTimeout(() => {
    popup.classList.add('saindo');
    setTimeout(() => popup.remove(), 600);
  }, 3500);
}

