async function salvarInfoOrkut() {
  const payload = {
    bio: document.getElementById('up-edit-bio').value.trim(),
    relacionamento: document.getElementById('up-edit-rel').value,
    identidade_sexual: document.getElementById('up-edit-sexo').value.trim(),
    musicas: document.getElementById('up-edit-musicas').value.trim(),
    filmes: document.getElementById('up-edit-filmes').value.trim(),
    livros: document.getElementById('up-edit-livros').value.trim(),
    esportes: document.getElementById('up-edit-esportes').value.trim(),
  };

  const { error } = await supabaseClient.from('profiles').update(payload).eq('id', currentUser.id);
  
  if (error) {
    mostrarNotificacao('Erro ao salvar dados.');
  } else {
    mostrarNotificacao('✅ Perfil Orkut atualizado!');
    Object.assign(currentProfile, payload);
  }
}

async function carregarRanking() {
  const lista = document.getElementById('up-ranking-lista');
  if(!lista) return;
  const {data, error} = await supabaseClient
    .from('profiles')
    .select('nickname, color, avatar_url, xp, level')
    .order('xp', {ascending:false})
    .limit(10);
  if(error||!data){lista.innerHTML='<div class="up-ranking-loading">Erro ao carregar.</div>';return;}
  lista.innerHTML = data.map((p,i)=>{
    const av = p.avatar_url
      ?`<img src="${p.avatar_url}" class="up-rank-avatar" alt="">`
      :`<div class="up-rank-avatar-inicial" style="background:${p.color||'#0000cc'}">${p.nickname.charAt(0).toUpperCase()}</div>`;
    const medal = i===0?'🥇':i===1?'🥈':i===2?'🥉':`<span class="up-rank-num" style="font-size:10px">${i+1}</span>`;
    const mine  = p.nickname===currentProfile.nickname;
    return `<div class="up-rank-row ${mine?'mine':''}">
      <div class="up-rank-medal">${medal}</div>
      ${av}
      <div class="up-rank-info">
        <span class="up-rank-nick" style="color:${p.color||'#0000cc'}">${escapeHtml(p.nickname)}</span>
        <span class="up-rank-level">${escapeHtml(p.level||'🥉 TV Globinho')}</span>
      </div>
      <div class="up-rank-xp">⭐ ${p.xp||0}</div>
    </div>`;
  }).join('');
}

async function carregarRankingTemporada() {
  const lista = document.getElementById('up-ranking-temporada');
  if(!lista || !temporadaAtiva) return;
  
  // Tenta buscar da tabela de snapshots da temporada, se não existir, mostra os top globais
  const {data, error} = await supabaseClient
    .from('season_snapshots')
    .select('nickname, color, avatar_url, xp, level')
    .eq('season_id', temporadaAtiva.id)
    .order('xp', {ascending:false})
    .limit(10);

  if(error || !data || data.length === 0){
    lista.innerHTML = '<div class="up-ranking-loading" style="font-style:italic;">Nenhum registro nesta temporada ainda.</div>';
    return;
  }
  
  lista.innerHTML = data.map((p,i)=>{
    const av = p.avatar_url
      ?`<img src="${p.avatar_url}" class="up-rank-avatar" alt="">`
      :`<div class="up-rank-avatar-inicial" style="background:${p.color||'#0000cc'}">${p.nickname.charAt(0).toUpperCase()}</div>`;
    const medal = i===0?'🥇':i===1?'🥈':i===2?'🥉':`<span class="up-rank-num" style="font-size:10px">${i+1}</span>`;
    return `<div class="up-rank-row">
      <div class="up-rank-medal">${medal}</div>
      ${av}
      <div class="up-rank-info">
        <span class="up-rank-nick" style="color:${p.color||'#0000cc'}">${escapeHtml(p.nickname)}</span>
        <span class="up-rank-level">${escapeHtml(p.level||'🥉 TV Globinho')}</span>
      </div>
      <div class="up-rank-xp" style="color:#1464d8;">⭐ ${p.xp||0}</div>
    </div>`;
  }).join('');
}

function copiarCupom(codigo) {
  navigator.clipboard.writeText(codigo).then(()=>{
    mostrarNotificacao('✅ Cupom copiado!');
  }).catch(()=>{
    mostrarNotificacao('Cupom: '+codigo);
  });
}

async function trocarAvatar(event) {
  const file = event.target.files[0]; if(!file) return;
  mostrarNotificacao('Enviando foto...');
  const compressedFile = await comprimirImagem(file, 200);
  let newAvatarUrl = null;
  try {
    newAvatarUrl = await uploadToCloudinary(compressedFile, 'avatars');
  } catch (e) {
    mostrarNotificacao('Erro ao fazer upload da foto.');
    return;
  }

  await supabaseClient.from('profiles').update({avatar_url:newAvatarUrl}).eq('id',currentUser.id);
  currentProfile.avatar_url = newAvatarUrl;
  // atualiza visual na janela de perfil. Cloudinary URLs are unique, no need for cache bust timestamp.
  const wrap = document.querySelector('.up-avatar-wrap');
  if(wrap) {
    const existing = wrap.querySelector('.up-avatar-img, .up-avatar-inicial');
    if(existing) existing.outerHTML = `<img src="${newAvatarUrl}" class="up-avatar-img" alt="">`;
  }
  mostrarNotificacao('✅ Foto atualizada!');
}


async function abrirWinamp() {
  fecharMenu();
  if (webampInstance) {
    trazerFrente('webamp-host');
    return;
  }

  mostrarAlerta('tutorial-winamp', 'Winamp', 'winamp', 
    `Sets gravados ao vivo nos eventos da Bad Idea, playlists dedicadas de cada festa, direto aqui.\n\n` +
    `Deixa tocando enquanto você navega pela plataforma.`, 
    'tutorial_winamp_visto');

  // Criamos um host invisível dentro do desktop para o Webamp
  let host = document.getElementById('webamp-host');
  if (!host) {
    host = document.createElement('div');
    host.id = 'webamp-host';
    document.querySelector('.desktop').appendChild(host);
  }

  // Carregamos a biblioteca Webamp dinamicamente se necessário
  if (typeof Webamp === 'undefined') {
    const script = document.createElement('script');
    script.src = "https://unpkg.com/webamp@1.5.0/built/webamp.bundle.min.js";
    script.onload = () => iniciarWebamp(host);
    document.head.appendChild(script);
  } else {
    iniciarWebamp(host);
  }
}

async function iniciarWebamp(host) {
  const { data: tracks, error } = await supabaseClient
    .from('winamp_playlist')
    .select('*')
    .eq('ativo', true)
    .order('ordem', { ascending: true });

  if (error) {
    mostrarNotificacao("Erro ao carregar rádio.");
    return;
  }

  // Mapear dados do Supabase para o formato do Webamp
  const webampTracks = tracks.map(t => ({
    metaData: {
      artist: t.artista || "Unknown",
      title: t.titulo
    },
    url: t.url
  }));

  if (webampInstance) {
    webampInstance.dispose();
  }

  zTop++;
  webampInstance = new Webamp({
    initialTracks: webampTracks,
    availableSkins: [
      { url: "https://unpkg.com/webamp@1.5.0/skins/base-2.91.wsz", name: "Winamp Classic" }
    ],
    zIndex: zTop
  });

  // Renderizar o Webamp dentro do nosso host
  await webampInstance.renderWhenReady(host);
  host.style.zIndex = zTop;

  // Trazer para frente ao clicar em qualquer parte do player
  host.addEventListener('mousedown', () => trazerFrente('webamp-host'));
  
  // Quando o usuário fechar o Winamp pelo próprio botão "X" dele
  webampInstance.onClose(() => {
    webampInstance.dispose();
    webampInstance = null;
    if (host) host.remove();
  });
}

